import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
  {
    variants: {
      variant: {
        default:
          "border-transparent bg-primary text-primary-foreground hover:bg-primary/80",
        secondary:
          "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80",
        destructive:
          "border-transparent bg-destructive text-destructive-foreground hover:bg-destructive/80",
        outline: "text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

export interface BadgeProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return (
    <div className={cn(badgeVariants({ variant }), className)} {...props} />
  )
}

export { Badge, badgeVariants }

import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive:
          "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        outline:
          "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-9 rounded-md px-3",
        lg: "h-11 rounded-md px-8",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button"
    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        {...props}
      />
    )
  }
)
Button.displayName = "Button"

export { Button, buttonVariants }

import { useCallback, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  useAppDispatch,
  useAppSelector,
  setCredentials,
  logout as logoutAction,
} from '@/store';
import { useLoginMutation, useRegisterMutation, useLogoutMutation } from '@/store/api';
import type { LoginDto, RegisterDto, User, AuthResponse } from '@/common/types';
import { UserRole } from '@/common/types/enums';
import { STORAGE_KEYS, ROUTE_PREFIX } from '@/lib/constants';
import { toast } from 'sonner';

export function useAuth() {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const { user, accessToken, refreshToken, isAuthenticated } = useAppSelector(
    (state) => state.auth,
  );

  const [loginMutation, { isLoading: isLoggingIn }] = useLoginMutation();
  const [registerMutation, { isLoading: isRegistering }] = useRegisterMutation();
  const [logoutMutation, { isLoading: isLoggingOut }] = useLogoutMutation();

  const login = useCallback(
    async (credentials: LoginDto) => {
      try {
        const result = await loginMutation(credentials).unwrap();
        const { user: loggedInUser, accessToken, refreshToken: rt } = result.data as AuthResponse;
        dispatch(
          setCredentials({
            user: loggedInUser,
            accessToken,
            refreshToken: rt,
          }),
        );
        toast.success(`Welcome back, ${loggedInUser.name}!`);
        // Navigate to appropriate portal based on role
        navigateToPortal(loggedInUser);
        return result;
      } catch (error: unknown) {
        const message =
          (error as { data?: { message?: string } })?.data?.message ||
          'Login failed. Please try again.';
        toast.error(message);
        throw error;
      }
    },
    [loginMutation, dispatch],
  );

  const register = useCallback(
    async (data: RegisterDto) => {
      try {
        const result = await registerMutation(data).unwrap();
        const { user: newUser, accessToken, refreshToken: rt } = result.data as AuthResponse;
        dispatch(
          setCredentials({
            user: newUser,
            accessToken,
            refreshToken: rt,
          }),
        );
        toast.success('Account created successfully!');
        navigateToPortal(newUser);
        return result;
      } catch (error: unknown) {
        const message =
          (error as { data?: { message?: string } })?.data?.message ||
          'Registration failed. Please try again.';
        toast.error(message);
        throw error;
      }
    },
    [registerMutation, dispatch],
  );

  const logout = useCallback(async () => {
    try {
      const rt = refreshToken || localStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN);
      if (rt) {
        await logoutMutation({ refreshToken: rt }).unwrap();
      }
    } catch {
      // Logout even if API call fails
    } finally {
      dispatch(logoutAction());
      navigate('/login', { replace: true });
      toast.success('Logged out successfully');
    }
  }, [logoutMutation, refreshToken, dispatch, navigate]);

  const navigateToPortal = useCallback(
    (u: User) => {
      switch (u.role) {
        case UserRole.SUPER_ADMIN:
          navigate(ROUTE_PREFIX.SUPER_ADMIN, { replace: true });
          break;
        case UserRole.ADMIN:
          navigate(ROUTE_PREFIX.ADMIN, { replace: true });
          break;
        case UserRole.SELLER:
          navigate(ROUTE_PREFIX.SELLER, { replace: true });
          break;
        default:
          navigate(ROUTE_PREFIX.CUSTOMER, { replace: true });
      }
    },
    [navigate],
  );

  const hasRole = useCallback(
    (roles: UserRole | UserRole[]) => {
      if (!user) return false;
      const roleArray = Array.isArray(roles) ? roles : [roles];
      return roleArray.includes(user.role);
    },
    [user],
  );

  const isAdmin = useMemo(
    () => hasRole([UserRole.ADMIN, UserRole.SUPER_ADMIN]),
    [hasRole],
  );

  const isSeller = useMemo(() => hasRole(UserRole.SELLER), [hasRole]);
  const isCustomer = useMemo(() => hasRole(UserRole.CUSTOMER), [hasRole]);
  const isSuperAdmin = useMemo(() => hasRole(UserRole.SUPER_ADMIN), [hasRole]);

  return {
    user,
    accessToken,
    refreshToken,
    isAuthenticated,
    isLoggingIn,
    isRegistering,
    isLoggingOut,
    login,
    register,
    logout,
    hasRole,
    isAdmin,
    isSeller,
    isCustomer,
    isSuperAdmin,
    navigateToPortal,
  };
}

import { useGetWarehousesQuery, useCreateWarehouseMutation, useDeleteWarehouseMutation } from '@/store/api';
import { PageHeader } from '@/common/components/PageHeader';
import { Card, CardContent, CardHeader, CardTitle } from '@/common/components/ui/card';
import { Button } from '@/common/components/ui/button';
import { Input } from '@/common/components/ui/input';
import { Label } from '@/common/components/ui/label';
import { Skeleton } from '@/common/components/ui/skeleton';
import { Badge } from '@/common/components/ui/badge';
import { Warehouse, Plus, MapPin, Trash2 } from 'lucide-react';
import { useState } from 'react';
import { toast } from 'sonner';

export default function AdminWarehousesPage() {
  const { data, isLoading, refetch } = useGetWarehousesQuery({});
  const [createWarehouse, { isLoading: creating }] = useCreateWarehouseMutation();
  const [deleteWarehouse] = useDeleteWarehouseMutation();

  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ name: '', code: '', address: '', city: '', country: '' });

  const warehouses = data?.data ?? [];

  const handleCreate = async () => {
    if (!form.name.trim() || !form.code.trim()) {
      toast.error('Name and code are required');
      return;
    }
    try {
      await createWarehouse(form).unwrap();
      toast.success('Warehouse created');
      setForm({ name: '', code: '', address: '', city: '', country: '' });
      setShowForm(false);
      refetch();
    } catch {
      toast.error('Failed to create warehouse');
    }
  };

  const handleDelete = async (id: string) => {
    try {
      await deleteWarehouse(id).unwrap();
      toast.success('Warehouse deleted');
      refetch();
    } catch {
      toast.error('Failed to delete warehouse');
    }
  };

  if (isLoading) {
    return (
      <div className="space-y-6">
        <PageHeader title="Warehouses" />
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
          {[1, 2, 3].map(i => <Skeleton key={i} className="h-40" />)}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <PageHeader title="Warehouses" />
        <Button onClick={() => setShowForm(!showForm)}>
          <Plus className="mr-2 h-4 w-4" /> Add Warehouse
        </Button>
      </div>

      {showForm && (
        <Card>
          <CardHeader>
            <CardTitle>New Warehouse</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid gap-4 md:grid-cols-2">
              <div className="space-y-2">
                <Label>Name *</Label>
                <Input value={form.name} onChange={(e) => setForm(p => ({ ...p, name: e.target.value }))} />
              </div>
              <div className="space-y-2">
                <Label>Code *</Label>
                <Input value={form.code} onChange={(e) => setForm(p => ({ ...p, code: e.target.value }))} placeholder="e.g., WH-01" />
              </div>
              <div className="space-y-2">
                <Label>Address</Label>
                <Input value={form.address} onChange={(e) => setForm(p => ({ ...p, address: e.target.value }))} />
              </div>
              <div className="space-y-2">
                <Label>City</Label>
                <Input value={form.city} onChange={(e) => setForm(p => ({ ...p, city: e.target.value }))} />
              </div>
              <div className="space-y-2">
                <Label>Country</Label>
                <Input value={form.country} onChange={(e) => setForm(p => ({ ...p, country: e.target.value }))} />
              </div>
            </div>
            <div className="flex gap-2">
              <Button onClick={handleCreate} disabled={creating}>
                {creating ? 'Creating...' : 'Create Warehouse'}
              </Button>
              <Button variant="outline" onClick={() => setShowForm(false)}>Cancel</Button>
            </div>
          </CardContent>
        </Card>
      )}

      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
        {warehouses.length === 0 ? (
          <Card className="col-span-full">
            <CardContent className="p-8 text-center text-muted-foreground">
              <Warehouse className="mx-auto h-12 w-12 mb-3" />
              <p>No warehouses configured yet</p>
            </CardContent>
          </Card>
        ) : (
          warehouses.map((wh: any) => (
            <Card key={wh.id}>
              <CardContent className="p-4 space-y-2">
                <div className="flex items-start justify-between">
                  <div className="flex items-center gap-2">
                    <Warehouse className="h-5 w-5 text-brand-500" />
                    <h3 className="font-medium">{wh.name}</h3>
                  </div>
                  <Button variant="ghost" size="icon" onClick={() => handleDelete(wh.id)}>
                    <Trash2 className="h-4 w-4 text-destructive" />
                  </Button>
                </div>
                <Badge variant="outline" className="font-mono">{wh.code}</Badge>
                {(wh.address || wh.city) && (
                  <p className="text-sm text-muted-foreground flex items-center gap-1">
                    <MapPin className="h-3 w-3" />
                    {[wh.address, wh.city, wh.country].filter(Boolean).join(', ')}
                  </p>
                )}
                <div className="text-xs text-muted-foreground">
                  Status: <Badge variant={wh.isActive !== false ? 'default' : 'secondary'}>
                    {wh.isActive !== false ? 'Active' : 'Inactive'}
                  </Badge>
                </div>
              </CardContent>
            </Card>
          ))
        )}
      </div>
    </div>
  );
}

import { useState } from 'react';
import { Link } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { Eye, EyeOff, Loader2, ShoppingBag } from 'lucide-react';
import { useAuth } from '@/common/hooks/useAuth';
import { registerSchema, type RegisterFormValues } from '@/common/schemas/auth.schema';
import { Button } from '@/common/components/ui/button';
import { Input } from '@/common/components/ui/input';
import { Label } from '@/common/components/ui/label';
import {
  Card,
  CardContent,
  CardFooter,
  CardHeader,
} from '@/common/components/ui/card';
import { Separator } from '@/common/components/ui/separator';
import { APP_NAME } from '@/lib/constants';

export default function RegisterPage() {
  const { register: registerUser, isRegistering } = useAuth();
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<RegisterFormValues>({
    resolver: zodResolver(registerSchema),
    defaultValues: {
      name: '',
      email: '',
      password: '',
      confirmPassword: '',
      phone: '',
    },
  });

  const onSubmit = async (data: RegisterFormValues) => {
    const { confirmPassword: _, ...dto } = data;
    await registerUser({
      name: dto.name,
      email: dto.email,
      password: dto.password,
      phone: dto.phone,
    });
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-gradient-to-b from-background to-muted/60 px-4 py-12">
      <div className="w-full max-w-sm space-y-6">
        {/* Logo */}
        <div className="text-center">
          <Link to="/" className="inline-flex items-center gap-2 text-2xl font-bold">
            <ShoppingBag className="h-8 w-8 text-[hsl(var(--amazon-orange))]" />
            <span>{APP_NAME}</span>
          </Link>
        </div>

        {/* Register Card */}
        <Card className="shadow-md">
          <CardHeader className="pb-4">
            <h1 className="text-xl font-semibold">Create account</h1>
          </CardHeader>

          <form onSubmit={handleSubmit(onSubmit)}>
            <CardContent className="space-y-4 pt-0">
              <div className="space-y-2">
                <Label htmlFor="name" className="text-sm font-semibold">Your name</Label>
                <Input
                  id="name"
                  placeholder="First and last name"
                  autoComplete="name"
                  disabled={isRegistering}
                  className="focus-visible:ring-[hsl(var(--amazon-orange))]"
                  {...register('name')}
                />
                {errors.name && (
                  <p className="text-xs text-destructive">{errors.name.message}</p>
                )}
              </div>

              <div className="space-y-2">
                <Label htmlFor="email" className="text-sm font-semibold">Email</Label>
                <Input
                  id="email"
                  type="email"
                  placeholder="name@example.com"
                  autoComplete="email"
                  disabled={isRegistering}
                  className="focus-visible:ring-[hsl(var(--amazon-orange))]"
                  {...register('email')}
                />
                {errors.email && (
                  <p className="text-xs text-destructive">{errors.email.message}</p>
                )}
              </div>

              <div className="space-y-2">
                <Label htmlFor="phone" className="text-sm font-semibold">Mobile number <span className="font-normal text-muted-foreground">(Optional)</span></Label>
                <Input
                  id="phone"
                  type="tel"
                  placeholder="+92XXXXXXXXXX"
                  autoComplete="tel"
                  disabled={isRegistering}
                  className="focus-visible:ring-[hsl(var(--amazon-orange))]"
                  {...register('phone')}
                />
                {errors.phone && (
                  <p className="text-xs text-destructive">{errors.phone.message}</p>
                )}
              </div>

              <div className="space-y-2">
                <Label htmlFor="password" className="text-sm font-semibold">Password</Label>
                <div className="relative">
                  <Input
                    id="password"
                    type={showPassword ? 'text' : 'password'}
                    placeholder="At least 6 characters"
                    autoComplete="new-password"
                    disabled={isRegistering}
                    className="focus-visible:ring-[hsl(var(--amazon-orange))]"
                    {...register('password')}
                  />
                  <Button
                    type="button"
                    variant="ghost"
                    size="icon"
                    className="absolute right-0 top-0 h-full px-3 hover:bg-transparent"
                    onClick={() => setShowPassword(!showPassword)}
                    tabIndex={-1}
                  >
                    {showPassword ? (
                      <EyeOff className="h-4 w-4 text-muted-foreground" />
                    ) : (
                      <Eye className="h-4 w-4 text-muted-foreground" />
                    )}
                  </Button>
                </div>
                {errors.password && (
                  <p className="text-xs text-destructive">{errors.password.message}</p>
                )}
              </div>

              <div className="space-y-2">
                <Label htmlFor="confirmPassword" className="text-sm font-semibold">Re-enter password</Label>
                <div className="relative">
                  <Input
                    id="confirmPassword"
                    type={showConfirmPassword ? 'text' : 'password'}
                    placeholder="Confirm your password"
                    autoComplete="new-password"
                    disabled={isRegistering}
                    className="focus-visible:ring-[hsl(var(--amazon-orange))]"
                    {...register('confirmPassword')}
                  />
                  <Button
                    type="button"
                    variant="ghost"
                    size="icon"
                    className="absolute right-0 top-0 h-full px-3 hover:bg-transparent"
                    onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                    tabIndex={-1}
                  >
                    {showConfirmPassword ? (
                      <EyeOff className="h-4 w-4 text-muted-foreground" />
                    ) : (
                      <Eye className="h-4 w-4 text-muted-foreground" />
                    )}
                  </Button>
                </div>
                {errors.confirmPassword && (
                  <p className="text-xs text-destructive">
                    {errors.confirmPassword.message}
                  </p>
                )}
              </div>

              <Button
                type="submit"
                className="w-full bg-[hsl(var(--amazon-orange))] hover:bg-[hsl(var(--amazon-orange-hover))] text-[hsl(var(--navy))] font-bold shadow-sm"
                disabled={isRegistering}
              >
                {isRegistering && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                Create your {APP_NAME} account
              </Button>
            </CardContent>

            <CardFooter className="flex flex-col pt-2 pb-6 px-6">
              <p className="text-xs text-muted-foreground text-center">
                By creating an account, you agree to {APP_NAME}'s Terms of Service and Privacy Policy.
              </p>
            </CardFooter>
          </form>
        </Card>

        {/* Divider */}
        <div className="relative">
          <Separator />
          <span className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 bg-background px-3 text-xs text-muted-foreground">
            Already have an account?
          </span>
        </div>

        {/* Sign In Button */}
        <Link to="/login" className="block">
          <Button variant="outline" className="w-full font-medium">
            Sign in
          </Button>
        </Link>
      </div>
    </div>
  );
}

import { useParams, Link } from 'react-router-dom';
import { useGetProductsQuery } from '@/store/api';
import { PageHeader } from '@/common/components/PageHeader';
import { Card, CardContent } from '@/common/components/ui/card';
import { Skeleton } from '@/common/components/ui/skeleton';
import { PriceDisplay } from '@/common/components/PriceDisplay';
import { EmptyState } from '@/common/components/EmptyState';
import { Package } from 'lucide-react';

export default function BrandPage() {
  const { brandId } = useParams<{ brandId: string }>();
  const { data, isLoading } = useGetProductsQuery({ brandId, limit: 50 });
  const products = data?.data?.items ?? [];

  if (isLoading) {
    return (
      <div className="space-y-6">
        <PageHeader title="Brand Products" />
        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
          {Array.from({ length: 8 }).map((_, i) => (
            <Skeleton key={i} className="h-72" />
          ))}
        </div>
      </div>
    );
  }

  if (!products.length) {
    return (
      <div className="space-y-6">
        <PageHeader title="Brand Products" />
        <EmptyState
          icon={<Package className="h-12 w-12" />}
          title="No products found"
          description="This brand doesn't have any products yet."
        />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <PageHeader title="Brand Products" />
      <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
        {products.map((product: any) => (
          <Link key={product.id} to={`/products/${product.slug}`}>
            <Card className="overflow-hidden hover:shadow-md transition-shadow">
              <div className="aspect-square bg-muted flex items-center justify-center">
                {product.images?.[0]?.url ? (
                  <img src={product.images[0].url} alt={product.name} className="h-full w-full object-cover" loading="lazy" />
                ) : (
                  <Package className="h-8 w-8 text-muted-foreground" />
                )}
              </div>
              <CardContent className="p-3">
                <p className="text-sm font-medium truncate">{product.name}</p>
                <PriceDisplay price={product.price} />
              </CardContent>
            </Card>
          </Link>
        ))}
      </div>
    </div>
  );
}

import { useParams, Link } from 'react-router-dom';
import { useGetBundleByIdQuery } from '@/store/api';
import { PageHeader } from '@/common/components/PageHeader';
import { Card, CardContent, CardHeader, CardTitle } from '@/common/components/ui/card';
import { Button } from '@/common/components/ui/button';
import { Skeleton } from '@/common/components/ui/skeleton';
import { PriceDisplay } from '@/common/components/PriceDisplay';
import { Badge } from '@/common/components/ui/badge';
import { formatCurrency } from '@/lib/format';
import { Package, ShoppingCart, Tag } from 'lucide-react';
import { useAddToCartMutation } from '@/store/api';
import { toast } from 'sonner';

export default function BundleDetailPage() {
  const { bundleId } = useParams<{ bundleId: string }>();
  const { data, isLoading } = useGetBundleByIdQuery(bundleId!, { skip: !bundleId });
  const [addToCart] = useAddToCartMutation();
  const bundle = data?.data;

  if (isLoading) {
    return (
      <div className="space-y-6">
        <PageHeader title="Bundle Details" />
        <Skeleton className="h-96" />
      </div>
    );
  }

  if (!bundle) {
    return (
      <div className="space-y-6 text-center py-12">
        <Package className="mx-auto h-12 w-12 text-muted-foreground" />
        <h2 className="text-xl font-semibold">Bundle not found</h2>
        <Button asChild><Link to="/bundles">View All Bundles</Link></Button>
      </div>
    );
  }

  const handleAddBundleToCart = async () => {
    try {
      for (const item of bundle.items ?? []) {
        await addToCart({ productId: item.productId, quantity: item.quantity ?? 1 }).unwrap();
      }
      toast.success('Bundle added to cart!');
    } catch {
      toast.error('Failed to add bundle to cart');
    }
  };

  return (
    <div className="space-y-6">
      <PageHeader title={bundle.name} />

      <div className="grid gap-6 lg:grid-cols-3">
        <div className="lg:col-span-2 space-y-6">
          <Card>
            <CardHeader>
              <div className="flex items-start justify-between">
                <div>
                  <CardTitle className="text-xl">{bundle.name}</CardTitle>
                  <p className="text-muted-foreground mt-1">{bundle.description}</p>
                </div>
                <Badge variant="secondary" className="shrink-0">
                  <Tag className="mr-1 h-3 w-3" />
                  {bundle.discountType === 'percentage' ? `${bundle.discountValue}% OFF` : `${formatCurrency(bundle.discountValue)} OFF`}
                </Badge>
              </div>
            </CardHeader>
            <CardContent>
              <h3 className="font-medium mb-3">Included Products</h3>
              <div className="divide-y">
                {bundle.items?.map((item: any) => (
                  <div key={item.id} className="flex items-center gap-4 py-3">
                    <div className="h-16 w-16 rounded-md bg-muted flex items-center justify-center">
                      <Package className="h-6 w-6 text-muted-foreground" />
                    </div>
                    <div className="flex-1">
                      <Link to={`/products/${item.product?.slug ?? item.productId}`} className="font-medium hover:underline">
                        {item.product?.name ?? 'Product'}
                      </Link>
                      <p className="text-sm text-muted-foreground">Qty: {item.quantity ?? 1}</p>
                    </div>
                    {item.product?.price && <PriceDisplay price={item.product.price} />}
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        </div>

        <Card className="h-fit sticky top-24">
          <CardContent className="p-6 space-y-4">
            <div className="text-center">
              <p className="text-sm text-muted-foreground">Bundle Price</p>
              <p className="text-3xl font-bold text-brand-600">{formatCurrency(bundle.bundlePrice ?? 0)}</p>
              {bundle.originalTotalPrice && (
                <p className="text-sm text-muted-foreground line-through">{formatCurrency(bundle.originalTotalPrice)}</p>
              )}
            </div>
            <Button onClick={handleAddBundleToCart} className="w-full bg-brand-500 text-navy hover:bg-brand-600" size="lg">
              <ShoppingCart className="mr-2 h-4 w-4" /> Add Bundle to Cart
            </Button>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { useSearchParams, Link } from 'react-router-dom';
import { useGetCategoriesQuery } from '@/store/api';
import { PageHeader } from '@/common/components/PageHeader';
import { EmptyState } from '@/common/components/EmptyState';
import { Card, CardContent } from '@/common/components/ui/card';
import { Skeleton } from '@/common/components/ui/skeleton';
import { Input } from '@/common/components/ui/input';
import { FolderOpen, Search, ChevronRight } from 'lucide-react';
import { useState, useMemo } from 'react';
import type { Category } from '@/common/types';

export default function CategoriesPage() {
  const [searchParams] = useSearchParams();
  const parentId = searchParams.get('parent') ?? undefined;
  const [search, setSearch] = useState('');

  const { data, isLoading } = useGetCategoriesQuery();

  const allCategories: Category[] = data?.data ?? [];

  // Filter to show children of current parent (or root categories)
  const categories = useMemo(() => {
    let filtered = allCategories.filter((c) =>
      parentId ? c.parentId === parentId : !c.parentId
    );
    if (search.trim()) {
      const q = search.toLowerCase();
      filtered = allCategories.filter((c) => c.name.toLowerCase().includes(q));
    }
    return filtered;
  }, [allCategories, parentId, search]);

  const parentCategory = parentId ? allCategories.find((c) => c.id === parentId) : null;

  if (isLoading) {
    return (
      <div className="space-y-6">
        <PageHeader title="Categories" />
        <div className="grid gap-4 sm:grid-cols-2 md:grid-cols-3">
          {Array.from({ length: 9 }).map((_, i) => (
            <Skeleton key={i} className="h-32" />
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Breadcrumbs */}
      {parentCategory && (
        <div className="flex items-center gap-1 text-sm text-muted-foreground">
          <Link to="/categories" className="hover:text-foreground">
            All Categories
          </Link>
          <ChevronRight className="h-4 w-4" />
          <span className="text-foreground">{parentCategory.name}</span>
        </div>
      )}

      <PageHeader
        title={parentCategory?.name ?? 'Categories'}
        description={parentCategory?.description ?? 'Browse all product categories'}
      />

      {/* Search */}
      <div className="relative max-w-sm">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
        <Input
          placeholder="Search categories..."
          className="pl-10"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      {categories.length === 0 ? (
        <EmptyState
          icon={<FolderOpen className="h-12 w-12" />}
          title="No categories found"
          description={search ? 'Try a different search term.' : 'No categories available.'}
        />
      ) : (
        <div className="grid gap-4 sm:grid-cols-2 md:grid-cols-3">
          {categories.map((cat) => {
            const childCount = allCategories.filter((c) => c.parentId === cat.id).length;
            return (
              <Link
                key={cat.id}
                to={childCount > 0 ? `/categories?parent=${cat.id}` : `/products?categoryId=${cat.id}`}
              >
                <Card className="hover:border-primary/30 transition-colors h-full">
                  <CardContent className="flex items-center gap-4 py-6">
                    <div className="h-16 w-16 rounded-lg bg-muted flex items-center justify-center flex-shrink-0">
                      {cat.imageUrl ? (
                        <img
                          src={cat.imageUrl}
                          alt={cat.name}
                          loading="lazy"
                          decoding="async"
                          className="h-full w-full object-cover rounded-lg"
                        />
                      ) : (
                        <FolderOpen className="h-8 w-8 text-muted-foreground" />
                      )}
                    </div>
                    <div className="flex-1 min-w-0">
                      <h3 className="font-medium truncate">{cat.name}</h3>
                      {cat.description && (
                        <p className="text-sm text-muted-foreground line-clamp-2">
                          {cat.description}
                        </p>
                      )}
                      {childCount > 0 && (
                        <p className="text-xs text-muted-foreground mt-1">
                          {childCount} subcategor{childCount === 1 ? 'y' : 'ies'}
                        </p>
                      )}
                    </div>
                    <ChevronRight className="h-5 w-5 text-muted-foreground flex-shrink-0" />
                  </CardContent>
                </Card>
              </Link>
            );
          })}
        </div>
      )}
    </div>
  );
}

import { PageHeader } from '@/common/components/PageHeader';
import { EmptyState } from '@/common/components/EmptyState';
import { LoadingSpinner } from '@/common/components/LoadingSpinner';
import { Button } from '@/common/components/ui/button';
import { formatCurrency } from '@/lib/format';
import { GitCompare, X } from 'lucide-react';
import { Link, useNavigate } from 'react-router-dom';
import type { Product } from '@/common/types';
import {
  useGetComparisonQuery,
  useRemoveFromComparisonMutation,
  useGetProductsQuery,
} from '@/store/api';

export default function ComparisonPage() {
  const { data: compData, isLoading } = useGetComparisonQuery();
  const comparisons = compData?.data ?? [];
  const productIds = comparisons.flatMap((c) => c.productIds);

  // Fetch all products to filter locally ΓÇö a simplified approach
  const { data: productsData } = useGetProductsQuery({ page: 1, limit: 100 });
  const allProducts = productsData?.data?.items ?? [];
  const products = allProducts.filter((p: Product) => productIds.includes(p.id));

  const [removeFromComparison] = useRemoveFromComparisonMutation();
  const navigate = useNavigate();

  if (isLoading) return <LoadingSpinner label="Loading comparison..." />;

  if (productIds.length === 0) {
    return (
      <div className="space-y-6">
        <PageHeader title="Compare Products" />
        <EmptyState
          icon={<GitCompare className="h-10 w-10" />}
          title="No products to compare"
          description="Add products to compare using the compare button on product pages."
          action={{ label: 'Browse Products', onClick: () => navigate('/products') }}
        />
      </div>
    );
  }

  const attrs = ['price', 'avgRating', 'totalReviews', 'totalSales'] as const;
  const attrLabels: Record<string, string> = {
    price: 'Price',
    avgRating: 'Rating',
    totalReviews: 'Reviews',
    totalSales: 'Sales',
  };

  return (
    <div className="space-y-6">
      <PageHeader title="Compare Products" description={`Comparing ${products.length} products`} />

      <div className="overflow-x-auto">
        <table className="w-full border-collapse">
          <thead>
            <tr>
              <th className="border p-3 text-left">Feature</th>
              {products.map((p: Product) => (
                <th key={p.id} className="border p-3 text-center">
                  <div className="space-y-2">
                    <Link to={`/products/${p.slug}`} className="font-medium hover:underline">
                      {p.name}
                    </Link>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => removeFromComparison(p.id)}
                    >
                      <X className="h-4 w-4" />
                    </Button>
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {attrs.map((attr) => (
              <tr key={attr}>
                <td className="border p-3 font-medium">{attrLabels[attr]}</td>
                {products.map((p: Product) => (
                  <td key={p.id} className="border p-3 text-center">
                    {attr === 'price'
                      ? formatCurrency(p.price)
                      : String((p as unknown as Record<string, unknown>)[attr] ?? 'ΓÇö')}
                  </td>
                ))}
              </tr>
            ))}
            <tr>
              <td className="border p-3 font-medium">Category</td>
              {products.map((p: Product) => (
                <td key={p.id} className="border p-3 text-center">{(p as any).category?.name ?? 'ΓÇö'}</td>
              ))}
            </tr>
          </tbody>
        </table>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { PageHeader } from '@/common/components/PageHeader';
import { StatCard } from '@/common/components/StatCard';
import { DataTable } from '@/common/components/DataTable';
import { EmptyState } from '@/common/components/EmptyState';
import { LoadingSpinner } from '@/common/components/LoadingSpinner';
import { Button } from '@/common/components/ui/button';
import { Input } from '@/common/components/ui/input';
import { Badge } from '@/common/components/ui/badge';
import { Card, CardContent, CardHeader, CardTitle } from '@/common/components/ui/card';
import { formatDate, formatNumber } from '@/lib/format';
import { Star, Gift, Trophy, Copy, Users } from 'lucide-react';
import { toast } from 'sonner';
import type { ColumnDef } from '@tanstack/react-table';
import type { LoyaltyTransaction, LoyaltyTier } from '@/common/types';
import {
  useGetMyLoyaltyPointsQuery,
  useGetMyLoyaltyTransactionsQuery,
  useGetLoyaltyTiersQuery,
  useGetMyReferralCodeQuery,
  useApplyReferralMutation,
  useGetMyReferralsQuery,
  useRedeemPointsMutation,
} from '@/store/api';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/common/components/ui/dialog';

export default function CustomerLoyaltyPage() {
  const [showRedeem, setShowRedeem] = useState(false);
  const [redeemPoints, setRedeemPoints] = useState('');
  const [referralInput, setReferralInput] = useState('');

  const { data: pointsData, isLoading } = useGetMyLoyaltyPointsQuery();
  const points = pointsData?.data;

  const { data: txnData } = useGetMyLoyaltyTransactionsQuery({});
  const transactions = txnData?.data?.items ?? [];

  const { data: tiersData } = useGetLoyaltyTiersQuery();
  const tiers = (tiersData?.data ?? []) as LoyaltyTier[];

  const { data: codeData } = useGetMyReferralCodeQuery();
  const referralCode = codeData?.data;

  const { data: _referralsData } = useGetMyReferralsQuery();

  const [redeemPts] = useRedeemPointsMutation();
  const [applyRef] = useApplyReferralMutation();

  const handleRedeem = async () => {
    const pts = parseInt(redeemPoints);
    if (isNaN(pts) || pts <= 0) return;
    try {
      await redeemPts({ points: pts }).unwrap();
      toast.success('Points redeemed successfully!');
      setShowRedeem(false);
      setRedeemPoints('');
    } catch {
      toast.error('Failed to redeem points');
    }
  };

  const handleApplyReferral = async () => {
    if (!referralInput.trim()) return;
    try {
      await applyRef(referralInput).unwrap();
      setReferralInput('');
      toast.success('Referral code applied!');
    } catch {
      toast.error('Failed to apply referral code');
    }
  };

  const copyCode = () => {
    if (referralCode?.code) {
      navigator.clipboard.writeText(referralCode.code);
      toast.success('Code copied to clipboard');
    }
  };

  const txnColumns: ColumnDef<LoyaltyTransaction, unknown>[] = [
    {
      accessorKey: 'type',
      header: 'Type',
      cell: ({ getValue }) => <Badge variant="outline">{getValue() as string}</Badge>,
    },
    {
      accessorKey: 'points',
      header: 'Points',
      cell: ({ getValue }) => {
        const pts = getValue() as number;
        return <span className={pts > 0 ? 'text-green-600' : 'text-red-600'}>{pts > 0 ? '+' : ''}{pts}</span>;
      },
    },
    { accessorKey: 'description', header: 'Description' },
    {
      accessorKey: 'createdAt',
      header: 'Date',
      cell: ({ getValue }) => formatDate(getValue() as string),
    },
  ];

  if (isLoading) return <LoadingSpinner label="Loading loyalty program..." />;

  return (
    <div className="space-y-6">
      <PageHeader title="Loyalty Program" description="Earn and redeem points">
        <Button onClick={() => setShowRedeem(true)} disabled={!points?.availableBalance}>
          Redeem Points
        </Button>
      </PageHeader>

      {/* Stats */}
      <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
        <StatCard icon={Star} title="Available Points" value={formatNumber(points?.availableBalance ?? 0)} />
        <StatCard icon={Trophy} title="Lifetime Points" value={formatNumber(points?.lifetimePoints ?? 0)} />
        <StatCard icon={Gift} title="Redeemed" value={formatNumber(points?.totalRedeemed ?? 0)} />
        <StatCard icon={Users} title="Referrals" value={referralCode?.totalReferrals ?? 0} />
      </div>

      {/* Referral Code Section */}
      {referralCode && (
        <Card>
          <CardHeader>
            <CardTitle className="text-lg">Your Referral Code</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="flex items-center gap-3">
              <code className="rounded bg-muted px-4 py-2 text-lg font-bold">{referralCode.code}</code>
              <Button variant="outline" size="sm" onClick={copyCode}>
                <Copy className="mr-1 h-4 w-4" /> Copy
              </Button>
            </div>
            <p className="mt-2 text-sm text-muted-foreground">
              Share your code to earn bonus points. {referralCode.totalReferrals} referrals so far.
            </p>
          </CardContent>
        </Card>
      )}

      {/* Apply Referral Code */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Apply Referral Code</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="flex gap-2">
            <Input
              placeholder="Enter referral code"
              value={referralInput}
              onChange={(e) => setReferralInput(e.target.value)}
            />
            <Button onClick={handleApplyReferral}>Apply</Button>
          </div>
        </CardContent>
      </Card>

      {/* Tiers */}
      {tiers.length > 0 && (
        <div>
          <h2 className="mb-3 text-lg font-semibold">Loyalty Tiers</h2>
          <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-4">
            {tiers.map((tier) => (
              <Card key={tier.id} className={points?.tierId === tier.id ? 'border-primary' : ''}>
                <CardContent className="p-4">
                  <div className="flex items-center gap-2">
                    {tier.colorHex && (
                      <div className="h-4 w-4 rounded-full" style={{ backgroundColor: tier.colorHex }} />
                    )}
                    <h3 className="font-semibold">{tier.name}</h3>
                  </div>
                  <p className="mt-1 text-sm text-muted-foreground">
                    {formatNumber(tier.minPoints)} ΓÇô {tier.maxPoints ? formatNumber(tier.maxPoints) : 'Γê₧'} pts
                  </p>
                  <p className="text-sm">Earn {tier.earnMultiplier}x points</p>
                  {points?.tierId === tier.id && (
                    <Badge className="mt-2">Current Tier</Badge>
                  )}
                </CardContent>
              </Card>
            ))}
          </div>
        </div>
      )}

      {/* Transactions */}
      <div>
        <h2 className="mb-3 text-lg font-semibold">Transaction History</h2>
        {transactions.length === 0 ? (
          <EmptyState
            icon={<Star className="h-10 w-10" />}
            title="No transactions"
            description="Your loyalty point transactions will appear here."
          />
        ) : (
          <DataTable columns={txnColumns} data={transactions} />
        )}
      </div>

      {/* Redeem Dialog */}
      <Dialog open={showRedeem} onOpenChange={setShowRedeem}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Redeem Points</DialogTitle>
          </DialogHeader>
          <p className="text-sm text-muted-foreground">
            Available: {formatNumber(points?.availableBalance ?? 0)} points
          </p>
          <Input
            type="number"
            placeholder="Points to redeem"
            value={redeemPoints}
            onChange={(e) => setRedeemPoints(e.target.value)}
          />
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowRedeem(false)}>Cancel</Button>
            <Button onClick={handleRedeem}>Redeem</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

