import { useMemo } from 'react';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, Legend,
  LineChart, Line,
} from 'recharts';
import { PageHeader } from '@/common/components/PageHeader';
import { StatCard } from '@/common/components/StatCard';
import { Card, CardContent, CardHeader, CardTitle } from '@/common/components/ui/card';
import { Skeleton } from '@/common/components/ui/skeleton';
import { useGetProductsQuery, useGetOrdersQuery } from '@/store/api';
import { DollarSign, Package, ShoppingCart, TrendingUp } from 'lucide-react';

const STATUS_COLORS: Record<string, string> = {
  PENDING: '#f59e0b',
  CONFIRMED: '#3b82f6',
  SHIPPED: '#8b5cf6',
  DELIVERED: '#22c55e',
  CANCELLED: '#ef4444',
};

export default function SellerAnalyticsPage() {
  const { data: productsData, isLoading: loadingProducts } = useGetProductsQuery({
    page: 1,
    limit: 1,
  });
  const { data: ordersData, isLoading: loadingOrders } = useGetOrdersQuery({
    page: 1,
    limit: 100,
  });

  const totalProducts = productsData?.data?.total ?? 0;
  const orders = ordersData?.data?.items ?? [];
  const totalOrders = ordersData?.data?.total ?? orders.length;

  const isLoading = loadingProducts || loadingOrders;

  // Compute revenue
  const totalRevenue = useMemo(
    () => orders.reduce((sum: number, o: any) => sum + Number(o.totalAmount ?? 0), 0),
    [orders],
  );

  // Orders by status for pie chart
  const statusData = useMemo(() => {
    const counts: Record<string, number> = {};
    orders.forEach((o: any) => {
      const s = o.status ?? 'UNKNOWN';
      counts[s] = (counts[s] ?? 0) + 1;
    });
    return Object.entries(counts).map(([name, value]) => ({ name, value }));
  }, [orders]);

  // Revenue over last 7 days for line chart
  const revenueByDay = useMemo(() => {
    const map: Record<string, number> = {};
    for (let i = 6; i >= 0; i--) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      map[d.toISOString().slice(0, 10)] = 0;
    }
    orders.forEach((o: any) => {
      const day = (o.createdAt ?? '').slice(0, 10);
      if (day in map) map[day] += Number(o.totalAmount ?? 0);
    });
    return Object.entries(map).map(([date, revenue]) => ({
      date: date.slice(5), // MM-DD
      revenue: Math.round(revenue * 100) / 100,
    }));
  }, [orders]);

  // Orders per day for bar chart
  const ordersPerDay = useMemo(() => {
    const map: Record<string, number> = {};
    for (let i = 6; i >= 0; i--) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      map[d.toISOString().slice(0, 10)] = 0;
    }
    orders.forEach((o: any) => {
      const day = (o.createdAt ?? '').slice(0, 10);
      if (day in map) map[day]++;
    });
    return Object.entries(map).map(([date, count]) => ({
      date: date.slice(5),
      orders: count,
    }));
  }, [orders]);

  return (
    <div className="space-y-6">
      <PageHeader title="Analytics" description="Overview of your store performance" />

      {/* KPI Cards */}
      <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
        {isLoading ? (
          Array.from({ length: 4 }).map((_, i) => <Skeleton key={i} className="h-28" />)
        ) : (
          <>
            <StatCard title="Total Products" value={totalProducts} icon={Package} />
            <StatCard title="Total Orders" value={totalOrders} icon={ShoppingCart} />
            <StatCard
              title="Revenue"
              value={`$${totalRevenue.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`}
              icon={DollarSign}
            />
            <StatCard
              title="Avg Order Value"
              value={totalOrders > 0 ? `$${(totalRevenue / totalOrders).toFixed(2)}` : 'ΓÇö'}
              icon={TrendingUp}
            />
          </>
        )}
      </div>

      {/* Charts */}
      <div className="grid gap-6 lg:grid-cols-2">
        {/* Revenue Over Time */}
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Revenue (Last 7 Days)</CardTitle>
          </CardHeader>
          <CardContent>
            {isLoading ? (
              <Skeleton className="h-64 w-full" />
            ) : (
              <ResponsiveContainer width="100%" height={260}>
                <LineChart data={revenueByDay}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="date" fontSize={12} />
                  <YAxis fontSize={12} />
                  <Tooltip formatter={(v: any) => [`$${Number(v).toFixed(2)}`, 'Revenue']} />
                  <Line type="monotone" dataKey="revenue" stroke="#3b82f6" strokeWidth={2} dot={{ r: 4 }} />
                </LineChart>
              </ResponsiveContainer>
            )}
          </CardContent>
        </Card>

        {/* Orders by Status */}
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Orders by Status</CardTitle>
          </CardHeader>
          <CardContent>
            {isLoading ? (
              <Skeleton className="h-64 w-full" />
            ) : statusData.length === 0 ? (
              <div className="flex h-64 items-center justify-center text-muted-foreground">No orders yet</div>
            ) : (
              <ResponsiveContainer width="100%" height={260}>
                <PieChart>
                  <Pie data={statusData} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={90} label>
                    {statusData.map((entry) => (
                      <Cell key={entry.name} fill={STATUS_COLORS[entry.name] ?? '#94a3b8'} />
                    ))}
                  </Pie>
                  <Tooltip />
                  <Legend />
                </PieChart>
              </ResponsiveContainer>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Orders per Day Bar Chart */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base">Orders Per Day (Last 7 Days)</CardTitle>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <Skeleton className="h-48 w-full" />
          ) : (
            <ResponsiveContainer width="100%" height={200}>
              <BarChart data={ordersPerDay}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="date" fontSize={12} />
                <YAxis allowDecimals={false} fontSize={12} />
                <Tooltip />
                <Bar dataKey="orders" fill="#8b5cf6" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useGetSellerDocumentsQuery, useAddSellerDocumentMutation } from '@/store/api';
import { useAppSelector } from '@/store';
import { PageHeader } from '@/common/components/PageHeader';
import { Card, CardContent, CardHeader, CardTitle } from '@/common/components/ui/card';
import { Button } from '@/common/components/ui/button';
import { Skeleton } from '@/common/components/ui/skeleton';
import { Badge } from '@/common/components/ui/badge';
import { Input } from '@/common/components/ui/input';
import { Label } from '@/common/components/ui/label';
import { FileText, Upload, CheckCircle2, Clock, XCircle } from 'lucide-react';
import { useState } from 'react';
import { toast } from 'sonner';

export default function SellerDocumentsPage() {
  const sellerId = useAppSelector((s) => s.auth.user?.id) ?? '';
  const { data, isLoading } = useGetSellerDocumentsQuery(sellerId, { skip: !sellerId });
  const [addDocument, { isLoading: uploading }] = useAddSellerDocumentMutation();
  const documents = data?.data ?? [];

  const [docName, setDocName] = useState('');
  const [docUrl, setDocUrl] = useState('');
  const [docType, setDocType] = useState('identity');

  const handleSubmit = async () => {
    if (!docName.trim() || !docUrl.trim()) {
      toast.error('Please fill in all fields');
      return;
    }
    try {
      await addDocument({ sellerId, data: { documentUrl: docUrl, documentType: docType } }).unwrap();
      toast.success('Document uploaded successfully');
      setDocName('');
      setDocUrl('');
    } catch {
      toast.error('Failed to upload document');
    }
  };

  const statusIcon = (status: string) => {
    if (status === 'approved' || status === 'verified') return <CheckCircle2 className="h-4 w-4 text-green-500" />;
    if (status === 'rejected') return <XCircle className="h-4 w-4 text-red-500" />;
    return <Clock className="h-4 w-4 text-yellow-500" />;
  };

  if (isLoading) {
    return (
      <div className="space-y-6">
        <PageHeader title="Documents" />
        <Skeleton className="h-64" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <PageHeader title="Documents" />

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Upload className="h-5 w-5" /> Upload Document
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid gap-4 md:grid-cols-3">
            <div className="space-y-2">
              <Label>Document Name</Label>
              <Input value={docName} onChange={(e) => setDocName(e.target.value)} placeholder="e.g., Business License" />
            </div>
            <div className="space-y-2">
              <Label>Document URL</Label>
              <Input value={docUrl} onChange={(e) => setDocUrl(e.target.value)} placeholder="https://..." />
            </div>
            <div className="space-y-2">
              <Label>Type</Label>
              <select
                value={docType}
                onChange={(e) => setDocType(e.target.value)}
                className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
              >
                <option value="identity">Identity</option>
                <option value="business">Business</option>
                <option value="tax">Tax</option>
                <option value="bank">Bank</option>
                <option value="other">Other</option>
              </select>
            </div>
          </div>
          <Button onClick={handleSubmit} disabled={uploading}>
            {uploading ? 'Uploading...' : 'Upload Document'}
          </Button>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle>Your Documents</CardTitle>
        </CardHeader>
        <CardContent>
          {documents.length === 0 ? (
            <p className="text-center text-muted-foreground py-8">No documents uploaded yet</p>
          ) : (
            <div className="divide-y">
              {documents.map((doc: any) => (
                <div key={doc.id} className="flex items-center gap-3 py-3">
                  <FileText className="h-8 w-8 text-muted-foreground" />
                  <div className="flex-1">
                    <p className="text-sm font-medium">{doc.documentName ?? doc.name}</p>
                    <p className="text-xs text-muted-foreground capitalize">{doc.documentType ?? doc.type}</p>
                  </div>
                  <div className="flex items-center gap-2">
                    {statusIcon(doc.status ?? 'pending')}
                    <Badge variant="secondary" className="capitalize">{doc.status ?? 'pending'}</Badge>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

