import { useState } from 'react';
import {
  useGetLanguagesQuery, useDeleteLanguageMutation, useSetDefaultLanguageMutation,
  useGetCurrenciesQuery, useDeleteCurrencyMutation, useSetDefaultCurrencyMutation,
  useCreateLanguageMutation, useCreateCurrencyMutation,
} from '@/store/api';
import { DataTable } from '@/common/components/DataTable';
import { PageHeader } from '@/common/components/PageHeader';
import { ConfirmDialog } from '@/common/components/ConfirmDialog';
import { Button } from '@/common/components/ui/button';
import { Badge } from '@/common/components/ui/badge';
import { Input } from '@/common/components/ui/input';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/common/components/ui/tabs';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/common/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/common/components/ui/select';
import { Star, Trash2, Plus } from 'lucide-react';
import { toast } from 'sonner';
import type { ColumnDef } from '@tanstack/react-table';
import type { Language, Currency } from '@/common/types';

export default function SAI18nPage() {
  const [deleteType, setDeleteType] = useState<'language' | 'currency' | null>(null);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [showCreateLang, setShowCreateLang] = useState(false);
  const [showCreateCurr, setShowCreateCurr] = useState(false);
  const [langForm, setLangForm] = useState({ code: '', name: '', nativeName: '', direction: 'ltr' });
  const [currForm, setCurrForm] = useState({ code: '', name: '', symbol: '', exchangeRate: 1 });

  const { data: langsData, isLoading: langsLoading } = useGetLanguagesQuery({});
  const { data: currData, isLoading: currLoading } = useGetCurrenciesQuery({});
  const [deleteLang] = useDeleteLanguageMutation();
  const [deleteCurr] = useDeleteCurrencyMutation();
  const [setDefaultLang] = useSetDefaultLanguageMutation();
  const [setDefaultCurr] = useSetDefaultCurrencyMutation();
  const [createLang, { isLoading: creatingLang }] = useCreateLanguageMutation();
  const [createCurr, { isLoading: creatingCurr }] = useCreateCurrencyMutation();

  const languages: Language[] = langsData?.data ?? [];
  const currencies: Currency[] = currData?.data ?? [];

  const handleDefault = async (type: 'language' | 'currency', id: string) => {
    try {
      if (type === 'language') await setDefaultLang(id).unwrap();
      else await setDefaultCurr(id).unwrap();
      toast.success(`Default ${type} updated`);
    } catch {
      toast.error(`Failed to set default ${type}`);
    }
  };

  const handleDelete = async () => {
    if (!deleteId || !deleteType) return;
    try {
      if (deleteType === 'language') await deleteLang(deleteId).unwrap();
      else await deleteCurr(deleteId).unwrap();
      toast.success(`${deleteType === 'language' ? 'Language' : 'Currency'} deleted`);
      setDeleteId(null);
      setDeleteType(null);
    } catch {
      toast.error('Failed to delete');
    }
  };

  const langColumns: ColumnDef<Language, unknown>[] = [
    {
      accessorKey: 'name',
      header: 'Language',
      cell: ({ row }) => (
        <div>
          <p className="font-medium">{row.original.name}</p>
          <p className="text-xs text-muted-foreground">{row.original.nativeName}</p>
        </div>
      ),
    },
    { accessorKey: 'code', header: 'Code' },
    {
      accessorKey: 'direction',
      header: 'Direction',
      cell: ({ row }) => <Badge variant="outline">{row.original.direction}</Badge>,
    },
    {
      accessorKey: 'isDefault',
      header: 'Default',
      cell: ({ row }) =>
        row.original.isDefault ? (
          <Badge>Default</Badge>
        ) : (
          <Button variant="ghost" size="sm" onClick={() => handleDefault('language', row.original.id)}>
            <Star className="mr-1 h-3 w-3" /> Set Default
          </Button>
        ),
    },
    {
      accessorKey: 'isActive',
      header: 'Status',
      cell: ({ row }) => (
        <Badge variant={row.original.isActive ? 'default' : 'secondary'}>
          {row.original.isActive ? 'Active' : 'Inactive'}
        </Badge>
      ),
    },
    {
      id: 'actions',
      header: '',
      cell: ({ row }) =>
        !row.original.isDefault && (
          <Button
            variant="ghost"
            size="icon"
            onClick={() => { setDeleteType('language'); setDeleteId(row.original.id); }}
          >
            <Trash2 className="h-4 w-4" />
          </Button>
        ),
    },
  ];

  const currColumns: ColumnDef<Currency, unknown>[] = [
    {
      accessorKey: 'name',
      header: 'Currency',
      cell: ({ row }) => (
        <div>
          <p className="font-medium">{row.original.name}</p>
          <p className="text-xs text-muted-foreground">{row.original.symbol}</p>
        </div>
      ),
    },
    { accessorKey: 'code', header: 'Code' },
    {
      accessorKey: 'exchangeRate',
      header: 'Rate',
      cell: ({ row }) => row.original.exchangeRate?.toFixed(4) ?? 'ΓÇö',
    },
    {
      accessorKey: 'isDefault',
      header: 'Default',
      cell: ({ row }) =>
        row.original.isDefault ? (
          <Badge>Default</Badge>
        ) : (
          <Button variant="ghost" size="sm" onClick={() => handleDefault('currency', row.original.id)}>
            <Star className="mr-1 h-3 w-3" /> Set Default
          </Button>
        ),
    },
    {
      accessorKey: 'isActive',
      header: 'Status',
      cell: ({ row }) => (
        <Badge variant={row.original.isActive ? 'default' : 'secondary'}>
          {row.original.isActive ? 'Active' : 'Inactive'}
        </Badge>
      ),
    },
    {
      id: 'actions',
      header: '',
      cell: ({ row }) =>
        !row.original.isDefault && (
          <Button
            variant="ghost"
            size="icon"
            onClick={() => { setDeleteType('currency'); setDeleteId(row.original.id); }}
          >
            <Trash2 className="h-4 w-4" />
          </Button>
        ),
    },
  ];

  return (
    <div className="space-y-6">
      <PageHeader title="Internationalization" description="Manage languages, currencies, and translations" />

      <Tabs defaultValue="languages">
        <TabsList>
          <TabsTrigger value="languages">Languages ({languages.length})</TabsTrigger>
          <TabsTrigger value="currencies">Currencies ({currencies.length})</TabsTrigger>
        </TabsList>

        <TabsContent value="languages" className="mt-4">
          <div className="mb-4 flex justify-end">
            <Button onClick={() => setShowCreateLang(true)}><Plus className="mr-2 h-4 w-4" /> Add Language</Button>
          </div>
          <DataTable columns={langColumns} data={languages} isLoading={langsLoading} emptyTitle="No languages" />
        </TabsContent>

        <TabsContent value="currencies" className="mt-4">
          <div className="mb-4 flex justify-end">
            <Button onClick={() => setShowCreateCurr(true)}><Plus className="mr-2 h-4 w-4" /> Add Currency</Button>
          </div>
          <DataTable columns={currColumns} data={currencies} isLoading={currLoading} emptyTitle="No currencies" />
        </TabsContent>
      </Tabs>

      <ConfirmDialog
        open={!!deleteId}
        onOpenChange={(open) => { if (!open) { setDeleteId(null); setDeleteType(null); } }}
        title={`Delete ${deleteType === 'language' ? 'Language' : 'Currency'}`}
        description="This will permanently remove this item."
        onConfirm={handleDelete}
      />

      {/* Create Language Dialog */}
      <Dialog open={showCreateLang} onOpenChange={setShowCreateLang}>
        <DialogContent>
          <DialogHeader><DialogTitle>Add Language</DialogTitle></DialogHeader>
          <div className="space-y-3">
            <Input placeholder="Code (e.g. en)" value={langForm.code} onChange={(e) => setLangForm((f) => ({ ...f, code: e.target.value }))} />
            <Input placeholder="Name (e.g. English)" value={langForm.name} onChange={(e) => setLangForm((f) => ({ ...f, name: e.target.value }))} />
            <Input placeholder="Native name (optional)" value={langForm.nativeName} onChange={(e) => setLangForm((f) => ({ ...f, nativeName: e.target.value }))} />
            <Select value={langForm.direction} onValueChange={(v) => setLangForm((f) => ({ ...f, direction: v }))}>
              <SelectTrigger><SelectValue /></SelectTrigger>
              <SelectContent>
                <SelectItem value="ltr">LTR</SelectItem>
                <SelectItem value="rtl">RTL</SelectItem>
              </SelectContent>
            </Select>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowCreateLang(false)}>Cancel</Button>
            <Button disabled={creatingLang} onClick={async () => {
              if (!langForm.code || !langForm.name) { toast.error('Code and name required'); return; }
              try {
                await createLang({ code: langForm.code, name: langForm.name, nativeName: langForm.nativeName || undefined, direction: langForm.direction as any }).unwrap();
                toast.success('Language added');
                setShowCreateLang(false);
                setLangForm({ code: '', name: '', nativeName: '', direction: 'ltr' });
              } catch { toast.error('Failed to create language'); }
            }}>
              {creatingLang ? 'Creating...' : 'Create'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Create Currency Dialog */}
      <Dialog open={showCreateCurr} onOpenChange={setShowCreateCurr}>
        <DialogContent>
          <DialogHeader><DialogTitle>Add Currency</DialogTitle></DialogHeader>
          <div className="space-y-3">
            <Input placeholder="Code (e.g. USD)" value={currForm.code} onChange={(e) => setCurrForm((f) => ({ ...f, code: e.target.value }))} />
            <Input placeholder="Name (e.g. US Dollar)" value={currForm.name} onChange={(e) => setCurrForm((f) => ({ ...f, name: e.target.value }))} />
            <Input placeholder="Symbol (e.g. $)" value={currForm.symbol} onChange={(e) => setCurrForm((f) => ({ ...f, symbol: e.target.value }))} />
            <Input type="number" step="0.0001" placeholder="Exchange rate" value={currForm.exchangeRate} onChange={(e) => setCurrForm((f) => ({ ...f, exchangeRate: parseFloat(e.target.value) || 1 }))} />
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowCreateCurr(false)}>Cancel</Button>
            <Button disabled={creatingCurr} onClick={async () => {
              if (!currForm.code || !currForm.name || !currForm.symbol) { toast.error('Code, name and symbol required'); return; }
              try {
                await createCurr({ code: currForm.code, name: currForm.name, symbol: currForm.symbol, exchangeRate: currForm.exchangeRate }).unwrap();
                toast.success('Currency added');
                setShowCreateCurr(false);
                setCurrForm({ code: '', name: '', symbol: '', exchangeRate: 1 });
              } catch { toast.error('Failed to create currency'); }
            }}>
              {creatingCurr ? 'Creating...' : 'Create'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useMemo } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import {
  useGetPermissionsQuery,
  useCreatePermissionMutation,
  useDeletePermissionMutation,
  useGetRolesQuery,
} from '@/store/api';
import {
  createPermissionSchema,
  type CreatePermissionFormValues,
} from '@/common/schemas/permission.schema';
import { PageHeader } from '@/common/components/PageHeader';
import { ConfirmDialog } from '@/common/components/ConfirmDialog';
import { LoadingSpinner } from '@/common/components/LoadingSpinner';
import { Button } from '@/common/components/ui/button';
import { Input } from '@/common/components/ui/input';
import { Label } from '@/common/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/common/components/ui/select';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/common/components/ui/card';
import { Badge } from '@/common/components/ui/badge';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  DialogDescription,
} from '@/common/components/ui/dialog';
import { Loader2, Plus, Trash2, KeyRound } from 'lucide-react';
import { toast } from 'sonner';
import type { Permission } from '@/common/types';

const CRUD_ACTIONS = ['create', 'read', 'update', 'delete', 'manage', 'export'];

export default function SAPermissionsPage() {
  const [createOpen, setCreateOpen] = useState(false);
  const [bulkModule, setBulkModule] = useState('');
  const [bulkRoleId, setBulkRoleId] = useState('');
  const [deleteTarget, setDeleteTarget] = useState<string | null>(null);

  const { data: permData, isLoading } = useGetPermissionsQuery();
  const { data: rolesData } = useGetRolesQuery();
  const [createPermission, { isLoading: creating }] = useCreatePermissionMutation();
  const [deletePermission] = useDeletePermissionMutation();

  const allPermissions: Permission[] = permData?.data ?? [];
  const roles = rolesData?.data ?? [];

  const byModule = useMemo(() => {
    const map: Record<string, Permission[]> = {};
    for (const p of allPermissions) {
      const mod = p.module || 'General';
      if (!map[mod]) map[mod] = [];
      map[mod].push(p);
    }
    return map;
  }, [allPermissions]);

  const modules = Object.keys(byModule).sort();

  const {
    register,
    handleSubmit,
    reset,
    setValue,
    watch,
    formState: { errors },
  } = useForm<CreatePermissionFormValues>({
    resolver: zodResolver(createPermissionSchema),
    defaultValues: { roleId: '', module: '', action: '' },
  });

  const selectedAction = watch('action');
  const selectedRoleId = watch('roleId');

  const onSubmitPermission = async (data: CreatePermissionFormValues) => {
    try {
      await createPermission({
        roleId: data.roleId,
        module: data.module,
        action: data.action,
      }).unwrap();
      toast.success('Permission created');
      reset();
      setCreateOpen(false);
    } catch (err: unknown) {
      const message = (err as { data?: { message?: string } })?.data?.message || 'Failed to create permission';
      toast.error(message);
    }
  };

  const handleBulkCreate = async () => {
    if (!bulkModule.trim() || !bulkRoleId) {
      toast.error('Enter a module name and select a role');
      return;
    }
    const mod = bulkModule.trim().toLowerCase();
    let created = 0;
    for (const action of CRUD_ACTIONS) {
      // Skip if already exists
      const exists = allPermissions.some(
        (p) => p.module?.toLowerCase() === mod && p.action?.toLowerCase() === action,
      );
      if (exists) continue;
      try {
        await createPermission({
          roleId: bulkRoleId,
          module: mod,
          action,
        }).unwrap();
        created++;
      } catch {
        // ignore individual failures
      }
    }
    toast.success(`Created ${created} permissions for "${mod}"`);
    setBulkModule('');
  };

  const handleDelete = async () => {
    if (!deleteTarget) return;
    try {
      await deletePermission(deleteTarget).unwrap();
      toast.success('Permission deleted');
    } catch {
      toast.error('Failed to delete permission');
    } finally {
      setDeleteTarget(null);
    }
  };

  if (isLoading) return <LoadingSpinner />;

  return (
    <div className="space-y-6">
      <PageHeader title="Permissions" description={`${allPermissions.length} permissions across ${modules.length} modules`}>
        <Button onClick={() => setCreateOpen(true)}>
          <Plus className="mr-2 h-4 w-4" />
          Create Permission
        </Button>
      </PageHeader>

      {/* Bulk Create */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base">Bulk Create CRUD Permissions</CardTitle>
          <CardDescription>
            Instantly add create, read, update, delete, manage, and export permissions for a module
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex items-end gap-3">
            <div className="flex-1 space-y-2">
              <Label htmlFor="bulkModule">Module Name</Label>
              <Input
                id="bulkModule"
                placeholder="e.g. products, orders, reviews"
                value={bulkModule}
                onChange={(e) => setBulkModule(e.target.value)}
              />
            </div>
            <div className="flex-1 space-y-2">
              <Label>Role</Label>
              <Select value={bulkRoleId} onValueChange={setBulkRoleId}>
                <SelectTrigger>
                  <SelectValue placeholder="Select role" />
                </SelectTrigger>
                <SelectContent>
                  {roles.map((r) => (
                    <SelectItem key={r.id} value={r.id}>{r.displayName || r.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <Button onClick={handleBulkCreate} disabled={!bulkModule.trim() || !bulkRoleId}>
              Add CRUD Permissions
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Permissions grouped by module */}
      {modules.length === 0 ? (
        <Card>
          <CardContent className="py-12">
            <div className="flex flex-col items-center gap-2 text-muted-foreground">
              <KeyRound className="h-12 w-12" />
              <p className="font-medium">No permissions defined</p>
              <p className="text-sm">Create permissions to control access across modules.</p>
            </div>
          </CardContent>
        </Card>
      ) : (
        modules.map((mod) => (
          <Card key={mod}>
            <CardHeader>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <CardTitle className="text-base capitalize">{mod}</CardTitle>
                  <Badge variant="outline">{byModule[mod].length}</Badge>
                </div>
              </div>
            </CardHeader>
            <CardContent>
              <div className="grid gap-2 sm:grid-cols-2 lg:grid-cols-3">
                {byModule[mod].map((perm) => (
                  <div
                    key={perm.id}
                    className="flex items-center justify-between rounded-md border p-2"
                  >
                    <div>
                      <p className="text-sm font-medium">{perm.action}</p>
                      <p className="text-xs text-muted-foreground">{`${perm.module}:${perm.action}`}</p>
                    </div>
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={() => setDeleteTarget(perm.id)}
                      title="Delete permission"
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        ))
      )}

      {/* Create Permission Dialog */}
      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Create Permission</DialogTitle>
            <DialogDescription>Define a new permission for a specific module and action.</DialogDescription>
          </DialogHeader>
          <form onSubmit={handleSubmit(onSubmitPermission)} className="space-y-4">
            <div className="space-y-2">
              <Label>Role *</Label>
              <Select value={selectedRoleId} onValueChange={(v) => setValue('roleId', v)}>
                <SelectTrigger>
                  <SelectValue placeholder="Select role" />
                </SelectTrigger>
                <SelectContent>
                  {roles.map((r) => (
                    <SelectItem key={r.id} value={r.id}>{r.displayName || r.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {errors.roleId && <p className="text-xs text-destructive">{errors.roleId.message}</p>}
            </div>
            <div className="space-y-2">
              <Label htmlFor="perm-module">Module *</Label>
              <Input id="perm-module" placeholder="e.g. products" {...register('module')} />
              {errors.module && <p className="text-xs text-destructive">{errors.module.message}</p>}
            </div>
            <div className="space-y-2">
              <Label>Action *</Label>
              <Select value={selectedAction} onValueChange={(v) => setValue('action', v)}>
                <SelectTrigger>
                  <SelectValue placeholder="Select action" />
                </SelectTrigger>
                <SelectContent>
                  {CRUD_ACTIONS.map((a) => (
                    <SelectItem key={a} value={a}>
                      {a}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {errors.action && <p className="text-xs text-destructive">{errors.action.message}</p>}
            </div>
            <DialogFooter>
              <Button type="button" variant="outline" onClick={() => setCreateOpen(false)}>
                Cancel
              </Button>
              <Button type="submit" disabled={creating}>
                {creating && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                Create
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>

      <ConfirmDialog
        open={!!deleteTarget}
        onOpenChange={(o) => !o && setDeleteTarget(null)}
        title="Delete Permission"
        description="This will remove the permission from all roles that have it assigned. Continue?"
        onConfirm={handleDelete}
        destructive
      />
    </div>
  );
}

import { useState } from 'react';
import {
  useGetUsersQuery,
  useGetRolesQuery,
  useUpdateUserMutation,
} from '@/store/api';
import { PageHeader } from '@/common/components/PageHeader';
import { DataTable } from '@/common/components/DataTable';
import { UserAvatar } from '@/common/components/UserAvatar';
import { RoleBadge, RoleSelect } from '@/common/components/RoleSelect';
import { DEFAULT_PAGE, DEFAULT_LIMIT } from '@/lib/constants';
import { formatDate } from '@/lib/format';
import { Button } from '@/common/components/ui/button';
import { Checkbox } from '@/common/components/ui/checkbox';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  DialogDescription,
} from '@/common/components/ui/dialog';
import { Label } from '@/common/components/ui/label';
import { Loader2, UserCog } from 'lucide-react';
import { toast } from 'sonner';
import type { ColumnDef } from '@tanstack/react-table';
import type { User } from '@/common/types';

export default function SARoleAssignmentsPage() {
  const [page, setPage] = useState(DEFAULT_PAGE);
  const [limit, setLimit] = useState(DEFAULT_LIMIT);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [bulkRoleOpen, setBulkRoleOpen] = useState(false);
  const [bulkRole, setBulkRole] = useState('');

  const { data, isLoading } = useGetUsersQuery({ page, limit });
  const { data: _rolesData } = useGetRolesQuery();
  const [updateUser, { isLoading: updating }] = useUpdateUserMutation();

  const users = data?.data?.items ?? [];
  const total = data?.data?.total ?? 0;
  const totalPages = data?.data?.totalPages ?? 1;

  const toggleSelect = (id: string) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const toggleAll = () => {
    if (selectedIds.size === users.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(users.map((u) => u.id)));
    }
  };

  const handleBulkAssign = async () => {
    if (!bulkRole || selectedIds.size === 0) return;
    let success = 0;
    const ids = Array.from(selectedIds);
    for (const id of ids) {
      try {
        await updateUser({ id, data: { role: bulkRole } as Partial<User> }).unwrap();
        success++;
      } catch {
        // continue
      }
    }
    toast.success(`Updated role for ${success} of ${ids.length} users`);
    setSelectedIds(new Set());
    setBulkRoleOpen(false);
    setBulkRole('');
  };

  const columns: ColumnDef<User, unknown>[] = [
    {
      id: 'select',
      header: () => (
        <Checkbox
          checked={users.length > 0 && selectedIds.size === users.length}
          onCheckedChange={toggleAll}
        />
      ),
      cell: ({ row }) => (
        <Checkbox
          checked={selectedIds.has(row.original.id)}
          onCheckedChange={() => toggleSelect(row.original.id)}
        />
      ),
    },
    {
      accessorKey: 'name',
      header: 'User',
      cell: ({ row }) => (
        <div className="flex items-center gap-3">
          <UserAvatar name={row.original.name} image={row.original.profileImage} size="sm" />
          <div>
            <p className="font-medium">{row.original.name}</p>
            <p className="text-xs text-muted-foreground">{row.original.email}</p>
          </div>
        </div>
      ),
    },
    {
      accessorKey: 'role',
      header: 'Current Role',
      cell: ({ row }) => <RoleBadge role={row.original.role} />,
    },
    {
      accessorKey: 'createdAt',
      header: 'Joined',
      cell: ({ row }) => formatDate(row.original.createdAt),
    },
    {
      accessorKey: 'lastLoginAt',
      header: 'Last Login',
      cell: ({ row }) => row.original.lastLoginAt ? formatDate(row.original.lastLoginAt) : 'ΓÇö',
    },
  ];

  return (
    <div className="space-y-6">
      <PageHeader title="Role Assignments" description="View and bulk-assign roles to users">
        <Button
          disabled={selectedIds.size === 0}
          onClick={() => setBulkRoleOpen(true)}
        >
          <UserCog className="mr-2 h-4 w-4" />
          Assign Role ({selectedIds.size})
        </Button>
      </PageHeader>

      <DataTable
        columns={columns}
        data={users}
        isLoading={isLoading}
        emptyTitle="No users found"
        pagination={{
          page, limit, total, totalPages,
          onPageChange: setPage,
          onLimitChange: setLimit,
        }}
      />

      {/* Bulk Role Assignment Dialog */}
      <Dialog open={bulkRoleOpen} onOpenChange={setBulkRoleOpen}>
        <DialogContent className="sm:max-w-sm">
          <DialogHeader>
            <DialogTitle>Bulk Role Assignment</DialogTitle>
            <DialogDescription>
              Assign a role to {selectedIds.size} selected user{selectedIds.size > 1 ? 's' : ''}.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label>New Role</Label>
              <RoleSelect value={bulkRole} onChange={setBulkRole} />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setBulkRoleOpen(false)}>
              Cancel
            </Button>
            <Button onClick={handleBulkAssign} disabled={!bulkRole || updating}>
              {updating && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Assign Role
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { render, type RenderOptions } from '@testing-library/react';
import { Provider } from 'react-redux';
import { BrowserRouter } from 'react-router-dom';
import { configureStore } from '@reduxjs/toolkit';
import { baseApi } from '@/store/baseApi';
import authReducer from '@/store/slices/authSlice';
import uiReducer from '@/store/slices/uiSlice';
import cartReducer from '@/store/slices/cartSlice';
import userEvent from '@testing-library/user-event';
import type { ReactElement, ReactNode } from 'react';

export function createTestStore() {
  return configureStore({
    reducer: {
      [baseApi.reducerPath]: baseApi.reducer,
      auth: authReducer,
      ui: uiReducer,
      cart: cartReducer,
    },
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    middleware: (getDefault: any) => getDefault().concat(baseApi.middleware),
  });
}

interface WrapperProps {
  children: ReactNode;
}

function AllProviders({ children }: WrapperProps) {
  const store = createTestStore();
  return (
    <Provider store={store}>
      <BrowserRouter>{children}</BrowserRouter>
    </Provider>
  );
}

export function renderWithProviders(
  ui: ReactElement,
  options?: Omit<RenderOptions, 'wrapper'>,
) {
  return render(ui, { wrapper: AllProviders, ...options });
}

export * from '@testing-library/react';
export { renderWithProviders as render };
export { userEvent };

import type { Config } from 'tailwindcss';

const config: Config = {
  darkMode: ['class'],
  content: ['./index.html', './src/**/*.{ts,tsx}'],
  theme: {
  	container: {
  		center: true,
  		padding: '2rem',
  		screens: {
  			'2xl': '1400px'
  		}
  	},
  	extend: {
  		colors: {
  			border: 'hsl(var(--border))',
  			input: 'hsl(var(--input))',
  			ring: 'hsl(var(--ring))',
  			background: 'hsl(var(--background))',
  			foreground: 'hsl(var(--foreground))',
  			primary: {
  				DEFAULT: 'hsl(var(--primary))',
  				foreground: 'hsl(var(--primary-foreground))'
  			},
  			secondary: {
  				DEFAULT: 'hsl(var(--secondary))',
  				foreground: 'hsl(var(--secondary-foreground))'
